       pager={this.props.pager}
       articles={this.props.articles}
       articlesCount={this.props.articlesCount}
       state={this.props.currentPage}
     />
     ```
   - Note: It passes `state` prop instead of `currentPage`

2. **`/src/components/Home/MainView.js`** (line 89)
   - Used in the `MainView` functional component
   - Props passed:
     ```jsx
     <ArticleList
       pager={props.pager}
