 * The header is only displayed when compassDesign is enabled.
 */
export const ModalHeader: React.FC<{
    compassDesign?: boolean;
    modalHeaderText?: React.ReactNode;
    headerButton?: React.ReactNode;
}> = ({compassDesign, modalHeaderText, headerButton}) => {
    const headerText = modalHeaderText && (
        <div className='GenericModal__header'>
            <h1 id='genericModalLabel'>
                {modalHeaderText}
            </h1>
            {headerButton}
        </div>
    );

    return (
        <Modal.Header closeButton={true}>
            {compassDesign && headerText}
        </Modal.Header>
    );
};

/**
 * ModalBody Sub-Component
 *
 * Renders the main body of the modal containing:
 * - Modal header (when not using compassDesign)
 * - Error text (when using compassDesign)
 * - Main content/children
 */
export const ModalBody: React.FC<{
    compassDesign?: boolean;
    errorText?: string;
    modalHeaderText?: React.ReactNode;
    headerButton?: React.ReactNode;
    children: React.ReactNode;
}> = ({compassDesign, errorText, modalHeaderText, headerButton, children}) => {
    const headerText = modalHeaderText && (
        <div className='GenericModal__header'>
            <h1 id='genericModalLabel'>
                {modalHeaderText}
            </h1>
            {headerButton}
        </div>
    );

    return (
        <Modal.Body>
            {compassDesign ? (
                errorText && (
                    <div className='genericModalError'>
                        <i className='icon icon-alert-outline'/>
                        <span>{errorText}</span>
                    </div>
                )
            ) : (
                headerText
            )}
            <div className='GenericModal__body'>
                {children}
            </div>
        </Modal.Body>
    );
};

/**
 * ModalFooter Sub-Component
 *
 * Renders the footer section of the modal containing action buttons.
 * Only renders if at least one button (cancel or confirm) is provided.
 */
export const ModalFooter: React.FC<{
    cancelButton?: React.ReactNode;
    confirmButton?: React.ReactNode;
}> = ({cancelButton, confirmButton}) => {
    if (!cancelButton && !confirmButton) {
        return null;
    }

    return (
        <Modal.Footer>
            {cancelButton}
            {confirmButton}
        </Modal.Footer>
    );
};

