type UseLoginFormOptions = {
  onSuccess: () => void;
};

export const useLoginForm = ({ onSuccess }: UseLoginFormOptions) => {
  const { addNotification } = useNotifications();
  const login = useLogin({
    onSuccess: () => {
      addNotification({
        type: 'success',
