  const login = useLogin({
    onSuccess: () => {
      addNotification({
        type: 'success',
        title: 'Logged in successfully',
      });
      onSuccess();
    },
    onError: (error: Error) => {
      addNotification({
        type: 'error',
        title: 'Failed to login',
        description: error.message,
      });
    },
  });

  const handleSubmit = (values: LoginInput) => {
    login.mutate(values);
  };

  return {
